import{_ as e,c as t,o as a,a as i}from"./app.02dba1cd.js";const g=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[{"level":2,"title":"What is It ?","slug":"what-is-it","link":"#what-is-it","children":[]},{"level":2,"title":"Why ?","slug":"why","link":"#why","children":[]}],"relativePath":"introduction.md"}'),o={name:"introduction.md"},n=i('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-hidden="true">#</a></h1><p>Pinia entity store started with the use of pinia during a project with a relational database. For each entity sent by the backend, corresponds a store created by Pinia. At the beginning, we had created a folder filled with function utils files allowing to make a crud with the data stored in pinia. During development, we quickly realized that the functions were repeated in each of the stores instantiated in the application. We therefore decided to create this package so as not to have to write the same functions for creation, suppression, update, etc. for each store, for each project.</p><p>We finally created stores with out of the box getters and setters for in-app instantiated stores</p><h2 id="what-is-it" tabindex="-1">What is It ? <a class="header-anchor" href="#what-is-it" aria-hidden="true">#</a></h2><p>Entity Store is a very lightweight package that looks like an orm without having to learn a complex api from a real orm</p><h2 id="why" tabindex="-1">Why ? <a class="header-anchor" href="#why" aria-hidden="true">#</a></h2><p>You can use entity store, on a project with <a href="https://vuejs.org/" target="_blank" rel="noreferrer">Vue 3</a> and <a href="https://pinia.vuejs.org/introduction.html" target="_blank" rel="noreferrer">Pinia</a> as state management !</p><p>It allows you to have standardized states with useful keys to manage your data. A set of basic functions (getters, setters) helps you focus on the real purpose of the application instead of wasting time managing your give in the store</p><p>And like Pinia, it&#39;s a <code>fully typed</code> lightweight package to manage relational entities. No need to create custom complex wrappers to support TypeScript, everything is typed and the API is designed in a way to leverage TS type inference as much as possible. Import the functions, call them, enjoy autocompletion!</p>',9),r=[n];function s(h,c,d,l,p,u){return a(),t("div",null,r)}const _=e(o,[["render",s]]);export{g as __pageData,_ as default};
